import React, { useState } from "react";
import { Form } from "react-bootstrap";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";

const MODULES = {
  "scheme-type": {
    title: "Scheme Type",
    iconBg: "#e7eefc",
    iconColor: "#3b6fe0",
    labelColor: "#3b6fe0",
    count: 0,
    fields: [
      { label: "Scheme Type Name", type: "text", required: true, placeholder: "e.g. Central Scheme" },
      { label: "Code", type: "text", required: true, placeholder: "e.g. CS01" },
      { label: "Description", type: "textarea", placeholder: "Optional description" },
      { label: "Status", type: "select", options: ["Active", "Inactive"] },
    ],
  },
  "subsidy-type": {
    title: "Subsidy Type",
    iconBg: "#fce6e4",
    iconColor: "#d9483f",
    labelColor: "#d9483f",
    count: 0,
    fields: [
      { label: "Subsidy Type Name", type: "text", required: true, placeholder: "e.g. Capital Subsidy" },
      { label: "Code", type: "text", required: true, placeholder: "e.g. SUB01" },
      { label: "Subsidy Percentage", type: "number", placeholder: "e.g. 25" },
      { label: "Status", type: "select", options: ["Active", "Inactive"] },
    ],
  },
  "scheme-category": {
    title: "Scheme Category",
    iconBg: "#fdf3da",
    iconColor: "#e0a528",
    labelColor: "#e0a528",
    count: 0,
    fields: [
      { label: "Category Name", type: "text", required: true, placeholder: "e.g. Agriculture" },
      { label: "Parent Scheme Type", type: "select", options: ["Central Scheme", "State Scheme"] },
      { label: "Description", type: "textarea", placeholder: "Optional description" },
      { label: "Status", type: "select", options: ["Active", "Inactive"] },
    ],
  },
  "scheme-subcategory": {
    title: "Scheme Sub-Category",
    iconBg: "#e3f5ea",
    iconColor: "#2e9e63",
    labelColor: "#2e9e63",
    count: 0,
    fields: [
      { label: "Sub-Category Name", type: "text", required: true, placeholder: "e.g. Drip Irrigation" },
      { label: "Parent Category", type: "select", options: ["Agriculture", "Horticulture"] },
      { label: "Description", type: "textarea", placeholder: "Optional description" },
      { label: "Status", type: "select", options: ["Active", "Inactive"] },
    ],
  },
  vendors: {
    title: "Vendors",
    iconBg: "#ececec",
    iconColor: "#6b6b6b",
    labelColor: "#6b6b6b",
    count: 0,
    fields: [
      { label: "Vendor Name", type: "text", required: true, placeholder: "e.g. ABC Traders" },
      { label: "Contact Person", type: "text", placeholder: "e.g. Ramesh Kumar" },
      { label: "Phone", type: "text", placeholder: "e.g. 9876543210" },
      { label: "Email", type: "email", placeholder: "e.g. vendor@example.com" },
      { label: "Address", type: "textarea", placeholder: "Optional address" },
      { label: "Status", type: "select", options: ["Active", "Inactive"] },
    ],
  },
};
function ModuleButton({ id, mod, active, onClick }) {
  return (
    <button
      type="button"
      onClick={() => onClick(id)}
      className="module-btn"
      style={{
        display: "flex",
        alignItems: "center",
        gap: 14,
        width: "100%",
        background: "#fff",
        border: active ? `1px solid ${mod.labelColor}` : "1px solid #eceae6",
        borderRadius: 10,
        padding: "14px 16px",
        marginBottom: 14,
        textAlign: "left",
        boxShadow: active
          ? `0 0 0 2px ${mod.labelColor}26`
          : "0 1px 2px rgba(0,0,0,0.03)",
        transition: "box-shadow .15s ease, border-color .15s ease, transform .1s ease",
      }}
    >
      <span
        style={{
          width: 40,
          height: 40,
          borderRadius: 10,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          flexShrink: 0,
          fontSize: "1.05rem",
          background: mod.iconBg,
          color: mod.iconColor,
        }}
      >
        <i className="fa-solid fa-user"></i>
      </span>
      <span style={{ fontWeight: 600, fontSize: "0.97rem", color: mod.labelColor }}>
        {mod.title}
      </span>
      <span style={{ marginLeft: "auto", fontWeight: 700, fontSize: "1.05rem", color: "#222" }}>
        {mod.count}
      </span>
    </button>
  );
}

function EntryField({ field, fieldId }) {
  if (field.type === "textarea") {
    return (
      <textarea
        className="form-control"
        id={fieldId}
        rows={3}
        placeholder={field.placeholder || ""}
      />
    );
  }
  if (field.type === "select") {
    return (
      <select className="form-select" id={fieldId}>
        {field.options.map((opt) => (
          <option key={opt} value={opt}>
            {opt}
          </option>
        ))}
      </select>
    );
  }
  return (
    <input
      type={field.type}
      className="form-control"
      id={fieldId}
      placeholder={field.placeholder || ""}
      required={!!field.required}
    />
  );
}
function EntryForm({ moduleKey, mod, onCancel }) {
  const handleSubmit = (e) => {
    e.preventDefault();
    alert(`${mod.title} saved successfully (demo only — wire this up to your API).`);
  };

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", borderBottom: "1px solid #eee", paddingBottom: 14, marginBottom: 22, }} >
        <span style={{ width: 38, height: 38, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center", marginRight: 12, fontSize: "1rem", background: mod.iconBg, color: mod.iconColor, }} >
          <i className="fa-solid fa-user"></i>
        </span>
        <div>
          <h5 style={{ margin: 0, fontWeight: 700 }}>{mod.title} — New Entry</h5>
          <div style={{ color: "#888", fontSize: "0.85rem", marginTop: 2 }}>
            Fill in the details below and save to add a new {mod.title.toLowerCase()}.
          </div>
        </div>
      </div>

      <form onSubmit={handleSubmit} noValidate>
        <div className="row">
          {mod.fields.map((field, i) => {
            const fieldId = `${moduleKey}-field-${i}`;
            return (
              <div className="col-md-6 mb-3" key={fieldId}>
                <label htmlFor={fieldId} className="form-label fw-semibold">
                  {field.label} {field.required && <span className="text-danger">*</span>}
                </label>
                <EntryField field={field} fieldId={fieldId} />
              </div>
            );
          })}
        </div>
        <div className="d-flex gap-2 mt-3 pt-2 border-top">
          <button type="submit" className="btn btn-primary px-4">
            <i className="fa-solid fa-floppy-disk me-1"></i> Save
          </button>
          <button type="button" className="btn btn-outline-secondary px-4" onClick={onCancel}>
            Cancel
          </button>
        </div>
      </form>
    </div>
  );
}
function SchemeMastersForm({}) {
  const [activeModule, setActiveModule] = useState(null);
    
  return (
   <div className="card">
               <div className="card-header d-flex justify-content-between border-0">
                  <div className="header-title">
                     <h5 className="card-title m-0 fw-bold">Add Scheme Type</h5>
                     <small className="head-sub">Fill in the details below and save to add a new </small>
                  </div>
               </div>
               <div className="card-body" style={{minHeight:"600px"}}>
                  <div className="new-user-info">
                     <EntryForm moduleKey={activeModule} mod={MODULES[activeModule]} onCancel={() => setActiveModule(null)} />
                  </div>
               </div>
            </div>
  );
}

export default SchemeMastersForm;
